							return null !== $value && '' !== $value;
						}
					)
				)
			)

wp_safe_redirect(
				$this->context->admin_url(
					'dashboard',
					array_filter(
						array(
							'notification' => $notification,
							'panel'        => $panel,
						),
						function ( $value ) {
							return null !== $value && '' !== $value;
						}
